protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: throws in EF Core 9 Cosmos — manage indexing via Azure portal/Bicep.
    // Preserve old discriminator property name (EF9 default changed to "$type").
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");
